// Get AI Agent output text
const text = $input.first().json.output || "";

// Split text into clean lines
const lines = text.split(/\n+/).map(l => l.trim()).filter(Boolean);

// Helper to extract value after "key:"
const extract = (label) => {
  const line = lines.find(l => l.toLowerCase().startsWith(label.toLowerCase()));
  if (!line) return "";
  return line.split(":").slice(1).join(":").trim(); // handles texts with :
};

// Extract values exactly as the agent output them
const purpose = extract("purpose");
const amount = extract("amount");      // e.g., "250tk"
const quantity = extract("quantity");  // e.g., "1kg", "2 dozen", "3 litre"
const reason = extract("reason");

// Auto date
const now = new Date();
const date = `${now.getDate()}/${now.getMonth() + 1}/${now.getFullYear()}`;

// Output without modifying units
return [
  {
    json: {
      success: true,
      date,
      purpose,
      amount,      // kept as string with units
      quantity,    // kept as string with units
      reason,
      formatted: `${date} | ${purpose} | Amount: ${amount} | Qty: ${quantity} | reason: ${reason}`
    }
  }
];

// --- 1. CONFIGURATION AND HELPER FUNCTIONS ---

// Define the assumed currency units and their conversion factor to the base unit (1)
const CURRENCY_MULTIPLIERS = {
    // Standard conversion: 1 K = 1000 base units (e.g., 1000 BDT/USD)
    'K': 1000, 
    // Example for a specific currency suffix that might be misinterpreted as a multiplier
    'TK': 1 
};

// Array of month names (0-indexed)
const MONTH_NAMES = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
];

/**
 * Safely converts an amount string (e.g., "250tk", "150K", "50") to a number.
 * @param {string} amountString - The raw amount string from the input.
 * @returns {number} The numeric value of the amount, or 0 if parsing fails.
 */
const parseAmount = (amountString) => {
    if (!amountString || typeof amountString !== 'string') return 0;

    let str = amountString.toUpperCase().trim();
    let value = parseFloat(str);

    // If a simple float works, return it
    if (!isNaN(value)) return value;

    // Check for currency suffixes/multipliers
    for (const suffix in CURRENCY_MULTIPLIERS) {
        if (str.endsWith(suffix)) {
            // Remove the suffix and attempt to parse the numeric part
            let numericPart = str.slice(0, -suffix.length);
            value = parseFloat(numericPart);

            if (!isNaN(value)) {
                return value * CURRENCY_MULTIPLIERS[suffix];
            }
        }
    }

    return 0;
};

// --- 2. GET CURRENT DATE AND TIME ---

const now = new Date();
// Format for comparison: D/M/YYYY
const todayDateString = `${now.getDate()}/${now.getMonth() + 1}/${now.getFullYear()}`;
// Month and year for "running month" calculation (Month is 0-indexed: Jan=0, Dec=11)
const currentMonthIndex = now.getMonth();
const currentMonthName = MONTH_NAMES[currentMonthIndex]; // Retrieve the month name
const currentYear = now.getFullYear();

// --- 3. PARSE NEW TRANSACTION FROM AI AGENT OUTPUT ---

// Get AI Agent output text from the first input item
const text = $input.first().json.output || "";

// Split text into clean lines
const lines = text.split(/\n+/).map(l => l.trim()).filter(Boolean);

// Helper to extract value after "key:"
const extract = (label) => {
  const line = lines.find(l => l.toLowerCase().startsWith(label.toLowerCase()));
  if (!line) return "";
  return line.split(":").slice(1).join(":").trim();
};

const newPurpose = extract("purpose");
const newAmountStr = extract("amount");
const newQuantity = extract("quantity");
const newReason = extract("reason");

// Create the new transaction object
const newTransaction = {
    date: todayDateString,
    purpose: newPurpose,
    amount: newAmountStr,
    numericAmount: parseAmount(newAmountStr),
    quantity: newQuantity,
    reason: newReason
};

// --- 4. AGGREGATE SPENDING ---

let totalSpentThisMonth = 0;
let totalSpentToday = 0;
let todayDetails = [];

// Combine the new transaction with all historical inputs
const allTransactions = $input.all()
    .map(item => item.json) 
    .filter(item => item && item.date && item.amount) 
    .concat(newTransaction); 

// Loop through all transactions (historical + new)
for (const item of allTransactions) {
    const amount = item.numericAmount || parseAmount(item.amount); 

    if (amount > 0) {
        // A. Check for "Today"
        if (item.date === todayDateString) {
            totalSpentToday += amount;
            // Record where the money was spent today
            todayDetails.push({
                purpose: item.purpose,
                amount: amount,
                reason: item.reason || 'N/A'
            });
        }

        // B. Check for "Running Month"
        const itemDateParts = item.date.split('/');
        // Note: Months are 0-indexed in JS, so we use the retrieved month index for comparison
        const itemMonthIndex = parseInt(itemDateParts[1], 10) - 1; 
        const itemYear = parseInt(itemDateParts[2], 10);

        if (itemMonthIndex === currentMonthIndex && itemYear === currentYear) {
             totalSpentThisMonth += amount;
        }
    }
}

// --- 5. FINAL OUTPUT (Single Object with Date Context) ---

return [
    {
        json: {
            // Date Context
            currentDate: todayDateString,
            currentMonth: currentMonthName, // Now includes the name
            currentYear: currentYear,

            // Spending Totals and Details
            totalSpentThisMonth: totalSpentThisMonth,
            totalSpentToday: totalSpentToday,
            todayExpenditures: todayDetails,
        }
    }
];
